import { EnvConfig } from '@/constants/EnvConfig';

// Builds an absolute photo URL from a stored value. Stored values are now bare file names
// (e.g. "fe6d2f8ebe88447a97e5c3a14dbed0af.jpeg"), but legacy data may contain full URLs;
// pass those through unchanged.
export const ResolvePhotoUrl = (photo?: string | null, bustCache = false): string => {
    if (!photo) return '';
    if (/^https?:\/\//i.test(photo)) {
        return bustCache ? `${photo}?v=${Date.now()}` : photo;
    }
    const base = EnvConfig.PhotoBaseUrl?.endsWith('/') ? EnvConfig.PhotoBaseUrl : `${EnvConfig.PhotoBaseUrl}/`;
    const url = `${base}${photo}`;
    return bustCache ? `${url}?v=${Date.now()}` : url;
};
